section.sourcecode:
(W2) coin generation and blinding (wallet)
batch_seed = random(256) Persist batch_seed for i in 0..n: coin_seedᵢ = HKDF(uint32(i), batch_seed, "taler-withdrawal-coin-derivation", 64) blind_secretᵢ = coin_seedᵢ[32:] coinᵢ.priv = coin_seedᵢ[:32] coinᵢ.pub = Ed25519-GetPub(coinᵢ.priv) h_denomᵢ = Hash-Denom(denomᵢ) planchetᵢ = RSA-FDH-Blind(SHA-512(coinᵢ.pub), blind_secretᵢ, denomᵢ.pub) h_planchetᵢ = Hash-Planchet(planchetᵢ, denomᵢ) planchets = (⟨h_denomᵢ⟩, ⟨planchetᵢ⟩) msg = Gen-Msg(WALLET_RESERVE_WITHDRAW, ( Sum ⟨denomᵢ.value⟩ | Sum ⟨denomᵢ.fee_withdraw⟩ | SHA-512( ⟨h_planchetᵢ⟩ ) | uint256(0x0) | uint32(0x0) | uint32(0x0) )) sig = Ed25519-Sign(reserve.priv, msg)
// todo: exchange.git uses different derivation than wallet-core.git (above): ⟨coin_seedᵢ⟩ = HKDF(uint32(n), batch_seed, "taler-withdraw-secrets", 32*n) for i in 0..n: blind_secretᵢ = HKDF("bks", coin_seedᵢ, "", 32) coinᵢ.priv = HKDF("coin", coin_seedᵢ, "", 32)

